                r'(\d{4}-\d{1,2})',
            ]

            all_dates = []
            for date_pattern in date_patterns:
                matches = re.findall(date_pattern, context, re.IGNORECASE)
                all_dates.extend(matches)

            if all_dates:
                project_info['st'] = all_dates[0]
                if len(all_dates) > 1:
                    project_info['et'] = all_dates[-1]

            # Determine topic based on keywords
