        if line.isupper() and len(line) > 10:
            is_project = True
        elif any(pattern in line for pattern in patterns) and len(line) < 150:
            is_project = True
        elif '(FEMA' in line or '(CalJPIA' in line or '(CalOES' in line:
            is_project = True

